import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';

export default function Header() {
  const [isMobile, setIsMobile] = React.useState(false);
  const [isMenuOpen, setIsMenuOpen] = React.useState(false);

  React.useEffect(() => {
    const check = () => {
      setIsMobile(window.innerWidth <= 809);
    };
    check();
    window.addEventListener('resize', check);
    return () => window.removeEventListener('resize', check);
  }, []);

  const menuItems = [
    { name: 'Início', href: '#home' },
    { name: 'Serviços', href: '#services' },
    { name: 'Sobre', href: '#about' },
    { name: 'Contato', href: '#contact' },
  ];

  return (
    <header style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      zIndex: 100,
      backgroundColor: 'transparent',
    }}>
      <nav style={{
        maxWidth: '1400px',
        margin: '0 auto',
        padding: isMobile ? '16px 20px' : '20px 40px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
      }}>
        {/* Logo */}
        <a href="#home" style={{
          fontSize: isMobile ? '20px' : '24px',
          fontWeight: 600,
          color: '#FFFFFF',
          textDecoration: 'none',
          fontFamily: 'Inter, sans-serif',
          letterSpacing: '-0.02em',
          textShadow: '0 2px 8px rgba(0, 0, 0, 0.3)',
        }}>
          Clínica Estética
        </a>

        {/* Desktop Menu */}
        {!isMobile && (
          <div style={{
            display: 'flex',
            gap: '32px',
            alignItems: 'center',
          }}>
            {menuItems.map((item) => (
              <a
                key={item.name}
                href={item.href}
                style={{
                  color: '#FFFFFF',
                  textDecoration: 'none',
                  fontSize: '15px',
                  fontWeight: 500,
                  fontFamily: 'Inter, sans-serif',
                  transition: 'color 0.3s ease',
                  textShadow: '0 2px 8px rgba(0, 0, 0, 0.3)',
                }}
                onMouseEnter={(e) => { e.currentTarget.style.color = '#F7ECDF'; }}
                onMouseLeave={(e) => { e.currentTarget.style.color = '#FFFFFF'; }}
              >
                {item.name}
              </a>
            ))}
            <a
              href="#agendar"
              style={{
                backgroundColor: 'rgba(255, 255, 255, 0.95)',
                color: '#633B2C',
                padding: '10px 24px',
                borderRadius: '50px',
                textDecoration: 'none',
                fontSize: '15px',
                fontWeight: 600,
                fontFamily: 'Inter, sans-serif',
                border: '1px solid rgba(255, 255, 255, 0.3)',
                transition: 'all 0.3s ease',
                boxShadow: '0 2px 8px rgba(0, 0, 0, 0.15)',
              }}
              onMouseEnter={(e) => { 
                e.currentTarget.style.backgroundColor = '#FFFFFF';
                e.currentTarget.style.transform = 'translateY(-1px)';
              }}
              onMouseLeave={(e) => { 
                e.currentTarget.style.backgroundColor = 'rgba(255, 255, 255, 0.95)';
                e.currentTarget.style.transform = 'translateY(0)';
              }}
            >
              Agendar Consulta
            </a>
          </div>
        )}

        {/* Mobile Hamburger */}
        {isMobile && (
          <button
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            style={{
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              padding: '8px',
              display: 'flex',
              flexDirection: 'column',
              gap: '5px',
            }}
            aria-label="Menu"
          >
            <motion.div
              animate={{ rotate: isMenuOpen ? 45 : 0, y: isMenuOpen ? 8 : 0 }}
              style={{
                width: '24px',
                height: '2px',
                backgroundColor: '#FFFFFF',
                borderRadius: '2px',
                boxShadow: '0 2px 4px rgba(0, 0, 0, 0.2)',
              }}
            />
            <motion.div
              animate={{ opacity: isMenuOpen ? 0 : 1 }}
              style={{
                width: '24px',
                height: '2px',
                backgroundColor: '#FFFFFF',
                borderRadius: '2px',
                boxShadow: '0 2px 4px rgba(0, 0, 0, 0.2)',
              }}
            />
            <motion.div
              animate={{ rotate: isMenuOpen ? -45 : 0, y: isMenuOpen ? -8 : 0 }}
              style={{
                width: '24px',
                height: '2px',
                backgroundColor: '#FFFFFF',
                borderRadius: '2px',
                boxShadow: '0 2px 4px rgba(0, 0, 0, 0.2)',
              }}
            />
          </button>
        )}
      </nav>

      {/* Mobile Menu */}
      <AnimatePresence>
        {isMobile && isMenuOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ duration: 0.2 }}
            style={{
              backgroundColor: 'rgba(253, 247, 239, 0.98)',
              backdropFilter: 'blur(10px)',
              borderTop: '1px solid rgba(152, 106, 62, 0.1)',
            }}
          >
            <div style={{
              padding: '20px',
              display: 'flex',
              flexDirection: 'column',
              gap: '16px',
            }}>
              {menuItems.map((item) => (
                <a
                  key={item.name}
                  href={item.href}
                  onClick={() => setIsMenuOpen(false)}
                  style={{
                    color: '#633B2C',
                    textDecoration: 'none',
                    fontSize: '16px',
                    fontWeight: 500,
                    fontFamily: 'Inter, sans-serif',
                    padding: '12px 16px',
                    borderRadius: '12px',
                    transition: 'background-color 0.3s ease',
                  }}
                  onMouseEnter={(e) => { e.currentTarget.style.backgroundColor = 'rgba(152, 106, 62, 0.08)'; }}
                  onMouseLeave={(e) => { e.currentTarget.style.backgroundColor = 'transparent'; }}
                >
                  {item.name}
                </a>
              ))}
              <a
                href="#agendar"
                onClick={() => setIsMenuOpen(false)}
                style={{
                  backgroundColor: '#F7ECDF',
                  color: '#633B2C',
                  padding: '12px 24px',
                  borderRadius: '50px',
                  textDecoration: 'none',
                  fontSize: '16px',
                  fontWeight: 600,
                  fontFamily: 'Inter, sans-serif',
                  border: '1px solid rgba(152, 106, 62, 0.25)',
                  textAlign: 'center',
                  marginTop: '8px',
                }}
              >
                Agendar Consulta
              </a>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
}
