import React from 'react';
import { motion, useMotionValue, useAnimationFrame } from 'framer-motion';
import heroImage from './hero.png';


export default function Hero() {
  const [isMobile, setIsMobile] = React.useState(false);
  const [isTablet, setIsTablet] = React.useState(false);

  const rotation = useMotionValue(0);

  useAnimationFrame((t) => {
    rotation.set((t / 60000) * 360 % 360);
  });

  React.useEffect(() => {
    const check = () => {
      setIsMobile(window.innerWidth <= 809);
      setIsTablet(window.innerWidth >= 810 && window.innerWidth <= 1199);
    };
    check();
    window.addEventListener('resize', check);
    return () => window.removeEventListener('resize', check);
  }, []);

  const tratamentos = [
    { name: "Acne & Saúde da Pele" },
    { name: "Peelings Químicos" },
    { name: "Tratamentos a Laser" },
    { name: "Botox e Preenchimentos" },
    { name: "Rejuvenescimento da Pele" },
    { name: "Soluções para o Envelhecimento" },
    { name: "Cuidados com a Pigmentação" },
    { name: "Redução de Cicatrizes" },
    { name: "Tratamento da Queda de Cabelo" },
    { name: "Terapia PRP" },
    { name: "Hydrafacial" },
    { name: "Microagulhamento" },
    { name: "Clareamento da Pele" },
    { name: "Reparo de Danos Solares" },
    { name: "Tratamento do Melasma" },
    { name: "Renovação Cutânea" },
    { name: "Bioestimuladores" },
    { name: "Skinbooster" },
  ];

  // Ângulos exatos do design system (step de -20.0045°)
  const angles = [
    33.7995, 13.795, -6.2095, -26.214, -46.214, -66.2185,
    -86.223, -106.223, -126.227, -146.232, -166.232, -186.237,
    -206.237, -226.241, -246.245, -266.245, -286.25, -306.25
  ];

  // Dimensões responsivas do círculo
  const circleSize = isMobile ? 440 : isTablet ? 520 : 660;
  const armWidth   = isMobile ? 150 : isTablet ? 174 : 192;
  const armOffset  = armWidth / 2; // left: calc(50% - armOffset)
  const circleBottom = isMobile ? -230 : isTablet ? -320 : -450;

  return (
    <section style={{
      position: 'relative',
      minHeight: '100vh',
      overflow: 'hidden',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      paddingTop: isMobile ? '90px' : '160px',
      paddingBottom: isMobile ? '80px' : '200px',
      backgroundColor: '#FDF7EF',
    }}>

      {/* ── Imagem de fundo ── */}
      <div style={{ position: 'absolute', inset: 0, zIndex: 0 }}>
        <img
          src={heroImage}
          alt="Background"
          style={{ 
            width: '100%', 
            height: isMobile ? '110%' : '100%', 
            objectFit: 'cover', 
            objectPosition: isMobile ? 'center 40%' : '80% 30%' 
          }}
        />
        <div style={{
          position: 'absolute', inset: 0,
          backgroundColor: 'rgba(58, 34, 24, 0.48)'
        }} />
      </div>

      {/* ── Texto central ── */}
      <div style={{
        position: 'relative',
        zIndex: 10,
        textAlign: 'center',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        padding: '0 20px',
        maxWidth: isMobile ? '100%' : '1100px',
      }}>
        <motion.h1
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          style={{
            fontSize: isMobile ? '44px' : isTablet ? '68px' : '90px',
            fontWeight: isMobile ? 700 : 500,
            color: '#ffffff',
            lineHeight: '1.1em',
            letterSpacing: '-0.02em',
            fontFamily: 'Inter, sans-serif',
            textShadow: '0 4px 24px rgba(0,0,0,0.25)',
            margin: 0,
          }}
        >
          {isMobile ? (
            <>A pele saudável<br />e confiante<br />começa aqui</>
          ) : (
            <>A pele saudável e<br />confiante começa aqui</>
          )}
        </motion.h1>

        <motion.p
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.2 }}
          style={{
            marginTop: isMobile ? '14px' : '24px',
            fontSize: isMobile ? '15px' : '20px',
            color: 'rgba(255,255,255,0.88)',
            fontFamily: 'Inter, sans-serif',
            lineHeight: '1.3em',
            fontWeight: 400,
            textShadow: '0 2px 10px rgba(0,0,0,0.3)',
          }}
        >
          Dermatologia avançada e tratamentos<br />
          estéticos modernos projetados para melhorar
        </motion.p>
      </div>

      {/* ── Botões em arco (container girante) ── */}
      <motion.div
        style={{
          position: 'absolute',
          width: `${circleSize}px`,
          height: `${circleSize}px`,
          bottom: `${circleBottom}px`,
          left: '50%',
          x: '-50%',
          rotate: rotation,         // rotação contínua via useMotionValue
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 15,
        }}
      >
        {/* Arms dos tratamentos */}
        {tratamentos.map((tratamento, i) => (
          <div
            key={i}
            style={{
              position: 'absolute',
              top: '0%',
              left: `calc(50% - ${armOffset}px)`,
              width: `${armWidth}px`,
              height: '100%',
              display: 'flex',
              alignItems: 'flex-start',
              transform: `rotate(${angles[i]}deg)`,
            }}
          >
            {/* +90° para virar o braço → texto na horizontal */}
            <div style={{ transform: 'rotate(90deg)', width: `${armWidth}px` }}>
              <motion.div
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                transition={{
                  delay: 0.5 + i * 0.04,
                  duration: 0.3,
                  ease: [0.44, 0, 0.56, 1],
                }}
                style={{
                  backgroundColor: 'rgba(152,106,62,0.12)',
                  border: '1px solid rgba(255,255,255,0.30)',
                  borderRadius: '50px',
                  backdropFilter: 'blur(5px)',
                  WebkitBackdropFilter: 'blur(5px)',
                  padding: isMobile ? '6px 10px 6px 6px' : '8px 14px 8px 8px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                  width: `${armWidth}px`,
                  cursor: 'pointer',
                  boxSizing: 'border-box',
                }}
              >
                <div style={{
                  borderRadius: '100%',
                  width: isMobile ? '18px' : '22px',
                  height: isMobile ? '18px' : '22px',
                  overflow: 'hidden',
                  flexShrink: 0,
                }}>
                  <img
                    src={`https://i.pravatar.cc/100?img=${i + 10}`}
                    alt=""
                    style={{ display: 'block', width: '100%', height: '100%', objectFit: 'cover' }}
                  />
                </div>
                <p style={{
                  color: '#ffffff',
                  fontSize: isMobile ? '9px' : '11px',
                  fontWeight: 500,
                  fontFamily: 'Inter, sans-serif',
                  margin: 0,
                  whiteSpace: 'nowrap',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  maxWidth: isMobile ? '112px' : '142px',
                }}>
                  {tratamento.name}
                </p>
              </motion.div>
            </div>
          </div>
        ))}

      </motion.div>

      {/* ── Botão CTA — elemento independente, fora do container girante ── */}
      <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 1.5, duration: 0.5 }}
        style={{
          position: 'absolute',
          bottom: isMobile ? '25px' : '18px',
          left: isMobile ? '16.5%' : '42%',
          transform: 'translateX(-50%)',
          zIndex: 30,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          gap: '8px',
          pointerEvents: 'auto',
        }}
      >
        <span style={{
          fontSize: '18px',
          color: '#986A3E',
          opacity: 0.9,
          lineHeight: 1,
          display: 'block',
        }}>✿</span>

        <motion.a
          href="#service"
          style={{
            position: 'relative',
            backgroundColor: '#F7ECDF',
            color: '#633B2C',
            borderRadius: '50px',
            padding: isMobile ? '10px 22px' : '12px 28px',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            fontSize: isMobile ? '14px' : '15px',
            fontWeight: 600,
            fontFamily: 'Inter, sans-serif',
            whiteSpace: 'nowrap',
            textDecoration: 'none',
            cursor: 'pointer',
            border: '1px solid rgba(152,106,62,0.25)',
            transition: 'background-color 0.3s cubic-bezier(0.44,0,0.56,1)',
            boxShadow: '0 2px 20px rgba(99,59,44,0.12)',
            overflow: 'hidden',
          }}
          onMouseEnter={e => { e.currentTarget.style.backgroundColor = '#EFE0CC'; }}
          onMouseLeave={e => { e.currentTarget.style.backgroundColor = '#F7ECDF'; }}
        >
          <motion.div
            animate={{
              x: ['-100%', '300%'],
            }}
            transition={{
              duration: 2.5,
              repeat: Infinity,
              repeatDelay: 1,
              ease: "easeInOut",
            }}
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              width: '50px',
              height: '100%',
              background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.6), transparent)',
              transform: 'skewX(-20deg)',
              pointerEvents: 'none',
            }}
          />
          Explore nossos tratamentos
        </motion.a>
      </motion.div>

    </section>
  );
}